mapper.select:
SELECT * FROM doctor_feedback
WHERE deleted = 0
  AND used_for_training = 0
  AND quality_score >= #{minQualityScore}
ORDER BY created_time ASC
LIMIT #{limit}

SELECT COUNT(*) AS totalFeedbackCount, SUM(CASE WHEN used_for_training = 1 THEN 1 ELSE 0 END) AS usedForTrainingCount, SUM(CASE WHEN used_for_training = 0 THEN 1 ELSE 0 END) AS pendingTrainingCount, ROUND(AVG(CASE WHEN quality_score IS NOT NULL THEN quality_score ELSE 0 END), 2) AS averageQualityScore, SUM(CASE WHEN correction_type = 'CORRECTION' THEN 1 ELSE 0 END) AS correctionCount, SUM(CASE WHEN correction_type = 'ADDITION' THEN 1 ELSE 0 END) AS additionCount, SUM(CASE WHEN correction_type = 'DELETION' THEN 1 ELSE 0 END) AS deletionCount, COUNT(DISTINCT feedback_user_id) AS activeDoctorCount FROM doctor_feedback WHERE deleted = 0
AND DATE(created_time) >= #{startDate}
AND DATE(created_time) <= #{endDate}
AND department = #{department}

SELECT DATE(created_time) AS date, department AS department, COUNT(*) AS feedbackCount, SUM(CASE WHEN correction_type = 'CORRECTION' THEN 1 ELSE 0 END) AS correctionCount, SUM(CASE WHEN correction_type = 'ADDITION' THEN 1 ELSE 0 END) AS additionCount, SUM(CASE WHEN correction_type = 'DELETION' THEN 1 ELSE 0 END) AS deletionCount, SUM(CASE WHEN used_for_training = 1 THEN 1 ELSE 0 END) AS usedForTrainingCount, ROUND(AVG(CASE WHEN quality_score IS NOT NULL THEN quality_score ELSE 0 END), 2) AS avgQualityScore, COUNT(DISTINCT feedback_user_id) AS activeDoctorCount FROM doctor_feedback WHERE deleted = 0
AND DATE(created_time) >= #{startDate}
AND DATE(created_time) <= #{endDate}
AND department = #{department}
GROUP BY DATE(created_time)
, department
ORDER BY date

SELECT entity_type AS entityType, COUNT(*) AS feedbackCount, SUM(CASE WHEN correction_type = 'CORRECTION' THEN 1 ELSE 0 END) AS correctionCount, SUM(CASE WHEN correction_type = 'ADDITION' THEN 1 ELSE 0 END) AS additionCount, SUM(CASE WHEN correction_type = 'DELETION' THEN 1 ELSE 0 END) AS deletionCount, ROUND(AVG(CASE WHEN original_confidence IS NOT NULL THEN original_confidence ELSE 0 END), 4) AS avgOriginalConfidence, ROUND( SUM(CASE WHEN used_for_training = 1 THEN 1 ELSE 0 END) * 100.0 / NULLIF(COUNT(*), 0), 2 ) AS usedForTrainingRate FROM doctor_feedback WHERE deleted = 0
AND DATE(created_time) >= #{startDate}
AND DATE(created_time) <= #{endDate}
AND department = #{department}
GROUP BY entity_type ORDER BY feedbackCount DESC

SELECT
    correction_type AS correctionType,
    COUNT(*) AS count,
    ROUND(COUNT(*) * 100.0 / (SELECT COUNT(*) FROM doctor_feedback WHERE deleted = 0

            AND DATE(created_time) >= #{startDate}


            AND DATE(created_time) <= #{endDate}


            AND department = #{department}

    ), 2) AS percentage
FROM doctor_feedback
WHERE deleted = 0
  AND correction_type IS NOT NULL

    AND DATE(created_time) >= #{startDate}


    AND DATE(created_time) <= #{endDate}


    AND department = #{department}

GROUP BY correction_type
ORDER BY count DESC

SELECT feedback_user_id AS feedbackUserId, feedback_user_name AS feedbackUserName, department AS department, COUNT(*) AS feedbackCount, SUM(CASE WHEN correction_type = 'CORRECTION' THEN 1 ELSE 0 END) AS correctionCount, ROUND(AVG(CASE WHEN quality_score IS NOT NULL THEN quality_score ELSE 0 END), 2) AS avgQualityScore, ROUND( COUNT(*) * 1.0 + SUM(CASE WHEN quality_score IS NOT NULL THEN quality_score ELSE 0 END) * 0.5, 2 ) AS contributionScore FROM doctor_feedback WHERE deleted = 0 AND feedback_user_id IS NOT NULL
AND DATE(created_time) >= #{startDate}
AND DATE(created_time) <= #{endDate}
AND department = #{department}
GROUP BY feedback_user_id, feedback_user_name, department ORDER BY contributionScore DESC LIMIT #{limit}

SELECT department AS department, COUNT(*) AS feedbackCount, SUM(CASE WHEN used_for_training = 1 THEN 1 ELSE 0 END) AS usedForTrainingCount, ROUND(AVG(CASE WHEN quality_score IS NOT NULL THEN quality_score ELSE 0 END), 2) AS avgQualityScore FROM doctor_feedback WHERE deleted = 0 AND department IS NOT NULL
AND DATE(created_time) >= #{startDate}
AND DATE(created_time) <= #{endDate}
AND department = #{department}
GROUP BY department ORDER BY feedbackCount DESC
